#!/usr/bin/env pwsh\n# Deployment Helper Script - TextGenerator Online\n# Automatiserar GitHub push och förberedelser\n\n# Färger för output\n$Green = \"`e[32m\"\n$Yellow = \"`e[33m\"\n$Red = \"`e[31m\"\n$Reset = \"`e[0m\"\n\nfunction Write-Success {param([string]$Message); Write-Host \"$Green✓$Reset $Message\"}\nfunction Write-Info {param([string]$Message); Write-Host \"$Yellow ℹ$Reset $Message\"}\nfunction Write-Error {param([string]$Message); Write-Host \"$Red✗$Reset $Message\"}\n\nWrite-Host @\"\n╔════════════════════════════════════════╗\n║  TextGenerator Deployment Helper       ║\n║  Automatiserad Git Setup & Deployment  ║\n╚════════════════════════════════════════╝\n\"@ -ForegroundColor Cyan\n\n# Steg 1: Kontrollera Git\nWrite-Info \"Kontrollerar Git installation...\"\nif (-not (Get-Command git -ErrorAction SilentlyContinue)) {\n    Write-Error \"Git är inte installerad!\"\n    Write-Info \"Ladda ner från: https://git-scm.com/download/win\"\n    exit 1\n}\nWrite-Success \"Git är installerat\"\n\n# Steg 2: Sätt konfig\nWrite-Info \"Konfigurerar Git användare...\"\n$gitName = Read-Host \"Ange ditt namn (för Git commits)\"\n$gitEmail = Read-Host \"Ange din email (för Git commits)\"\n\ngit config --global user.name \"$gitName\"\ngit config --global user.email \"$gitEmail\"\nWrite-Success \"Git konfigurerad\"\n\n# Steg 3: Initiera Git repo lokalt\nWrite-Info \"Initierar lokalt Git repository...\"\nif (Test-Path \".git\") {\n    Write-Info \"Git repo redan initierat, skipping\"\n} else {\n    git init\n    Write-Success \"Git repo initierat\"\n}\n\n# Steg 4: Lägg till filer\nWrite-Info \"Lägger till alla filer...\"\ngit add .\nWrite-Success \"Filer adderade\"\n\n# Steg 5: Gör en commit\nWrite-Info \"Skapar initial commit...\"\ngit commit -m \"Initial gymnasiearbete deployment - TextGenerator AI with Railway & Supabase\" -q\nWrite-Success \"Commit skapad\"\n\n# Steg 6: Sätt GitHub remote\nWrite-Info \"\\nSätt GitHub repository URL...\"\nWrite-Info \"Format: https://github.com/DITTNAMN/gymnasiearbete-textgenerator.git\"\n$githubUrl = Read-Host \"Ange din GitHub repo URL\"\n\nif (git config --get remote.origin.url) {\n    Write-Info \"Remote 'origin' redan satt, uppdaterar...\"\n    git remote set-url origin \"$githubUrl\"\n} else {\n    git remote add origin \"$githubUrl\"\n}\nWrite-Success \"GitHub remote konfigurerad\"\n\n# Steg 7: Byt till main branch\nWrite-Info \"Byter till main branch...\"\ntry {\n    git branch -M main\n    Write-Success \"Branch ändrad till 'main'\"\n} catch {\n    Write-Info \"Main branch redan aktiv\"\n}\n\n# Steg 8: Push till GitHub\nWrite-Host \"\\n$Yellow═══════════════════════════════════════$Reset\"\nWrite-Host $Yellow \"VIKTIGT: Du kommer nu behöva auktorisera med GitHub\"\nWrite-Host $Yellow \"Antingen via Personal Access Token eller OAuth\"$Reset\nWrite-Host \"$Yellow═══════════════════════════════════════$Reset\\n\"\n\nWrite-Info \"Pushar kod till GitHub...\"\nWrite-Info \"(Detta kan ta 1-2 minuter första gången)\"\n\ntry {\n    git push -u origin main\n    Write-Success \"Kod pushad till GitHub!\"\n} catch {\n    Write-Error \"Push misslyckades!\"\n    Write-Info \"Möjliga orsaker:\"\n    Write-Info \"1. Ditt GitHub-lösenord är felaktigt\"\n    Write-Info \"2. Du behöver ett Personal Access Token istället för lösenord\"\n    Write-Info \"3. Internet-anslutningen är offline\"\n    Write-Info \"\\nSe GitHub -> Personal Access Tokens om du behöver token.\"\n    exit 1\n}\n\n# Steg 9: Verifiera\nWrite-Host \"\\n$Yellow═══════════════════════════════════════$Reset\"\nWrite-Success \"\\n✓ GitHub setup avslutad!\\n\"\nWrite-Host @\"\n$Yellow📋 Nästa steg:$Reset\n\n1. Gå till din GitHub repo: $githubUrl\n2. Verifiera att dina filer finnsdar\n3. Öppna QUICK_DEPLOY.md eller DEPLOY_ONLINE.md\n4. Följ instruktionerna för:\n   - Supabase database setup\n   - Hugging Face checkpoint upload\n   - Railway deployment\n\n$Green🎯 Lycka till med deploymentet!$Reset\n\"@\n\nWrite-Host \"$Yellow═══════════════════════════════════════$Reset\\n\"\n"